    torznabDownload: {
        parameters: {
            query: {
                /** @description feed credential; passkey is an accepted alias */
                apikey?: string;
                /** @description alias for apikey */
                passkey?: string;
                /** @description the opaque, AEAD-sealed download token from the feed */
                token: string;
            };
            header?: never;
            path: {
                /** @description the configured indexer slug */
                slug: string;
            };
            cookie?: never;
        };
        requestBody?: never;
        responses: {
            /** @description The torrent file (application/x-bittorrent) on success. Unlike the caps/search feed, the /dl route returns real HTTP status codes for gate failures (matching Jackett's DownloadController), so *arr surfaces them as transport errors rather than accepting a 200 that later fails as an invalid torrent file. */
            200: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/x-bittorrent": string;
                };
            };
            /** @description redirect to a resolved magnet URI (only ever a magnet, never an http link) */
            302: {
                headers: {
                    [name: string]: unknown;
                };
                content?: never;
            };
            /** @description a Torznab <error> element (XML) for an invalid or forged download token */
            400: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/xml": string;
                };
            };
            /** @description a Torznab <error> element (XML) for a missing or invalid API key (Jackett's DownloadController returns Unauthorized) */
            401: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/xml": string;
                };
            };
            /** @description a Torznab <error> element (XML) for an unknown/unsupported indexer, or a plain-text body when the resolved payload is not a valid torrent (the serve-boundary bencode check, mirroring Jackett's BencodeParser → NotFound, uses http.Error rather than the Torznab XML shape); the link/passkey is never echoed */
            404: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/xml": string;
                    "text/plain": string;
                };
            };
            /** @description a generic Torznab <error> element (XML); the link/passkey is never echoed */
            500: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/xml": string;
                };
            };
            /** @description a Torznab <error> element (XML) when the download proxy is not enabled (the feature is unavailable) */
            503: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    "application/xml": string;
                };
            };
        };
    };
